int _appSettingsIsarEstimateSize(
  AppSettingsIsar object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  bytesCount += 3 + object.currencyDisplay.name.length * 3;
  bytesCount += 3 + object.defaultViewMode.name.length * 3;
  bytesCount += 3 + object.language.name.length * 3;
  {
    final value = object.pinCode;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  bytesCount += 3 + object.theme.name.length * 3;
  bytesCount += 3 + object.userId.length * 3;
  return bytesCount;
}

